function skillIndexByKey(k){if(k==='1'||k==='numpad1')return 0;if(k==='2'||k==='numpad2')return 1;if(k==='3'||k==='numpad3')return 2;return-1}addEventListener('keydown',e=>{const k=e.key.toLowerCase();input.keys.add(k);if(['arrowleft','arrowright','arrowup','arrowdown',' ','1','2','3','numpad1','numpad2','numpad3'].includes(k))e.preventDefault();if(!IS_TOUCH){const idx=skillIndexByKey(k),sk=idx>=0?getEquippedSkills()[idx]:null;if(sk)useSkill(sk)}});addEventListener('keyup',e=>input.keys.delete(e.key.toLowerCase()));function setTouch(e){input.touching=true;input.targetX=clamp(e.clientX-GAME_LEFT,0,W);input.targetY=clamp(e.clientY,0,H)}canvas.addEventListener('pointerdown',e=>{if(!state.running||state.paused||state.gameOver)return;canvas.setPointerCapture&&canvas.setPointerCapture(e.pointerId);setTouch(e);e.preventDefault()},{passive:false});canvas.addEventListener('pointermove',e=>{if(!input.touching||state.paused||state.gameOver)return;setTouch(e);e.preventDefault()},{passive:false});canvas.addEventListener('pointerup',e=>{input.touching=false;e.preventDefault()},{passive:false});canvas.addEventListener('pointercancel',()=>input.touching=false);
function createBullet(x,y,ang,dmg,st,opt={}){if(state.bullets.length>MAX_BULLETS)state.bullets.shift();const crit=Math.random()<st.crit;state.bullets.push({x,y,vx:Math.cos(ang)*(opt.speed||st.bulletSpeed),vy:Math.sin(ang)*(opt.speed||st.bulletSpeed),r:opt.r||st.bulletSize,damage:dmg*(crit?2:1),life:opt.life||1.4,pierce:opt.pierce===undefined?st.pierce:opt.pierce,crit,color:opt.color||null,homing:!!opt.homing})}function nearestEnemies(n=1){return[...state.enemies].sort((a,b)=>sqr(a.x-player.x)+sqr(a.y-player.y)-sqr(b.x-player.x)-sqr(b.y-player.y)).slice(0,n)}function shoot(){const st=stats(),lv=weaponLevel();if(player.primaryWeapon==='missile'){sfx('missile');const count=1+Math.floor(lv/2),targets=nearestEnemies(Math.max(1,count));for(let i=0;i<count;i++){const t=targets[i%Math.max(1,targets.length)],a=t?Math.atan2(t.y-player.y,t.x-player.x):(-Math.PI/2+rand(-.45,.45));createBullet(player.x,player.y-16,a,st.damage*(2+lv*.42),st,{speed:520+lv*28,r:st.bulletSize+2,life:2.5,color:'#ffe66d',pierce:0,homing:true})}return}if(player.primaryWeapon==='laser'){sfx('laser');state.lasers.push({x:player.x,w:18+lv*4,life:.26+lv*.04,dmg:st.damage*(1.25+lv*.48),tick:0});return}if(player.primaryWeapon==='heavy'){sfx('heavy');createBullet(player.x,player.y-18,-Math.PI/2,st.damage*(3.1+lv*.55),st,{speed:520+lv*18,r:st.bulletSize+6+lv*1.2,life:1.85,color:'#ff9966',pierce:1+Math.floor(lv/2)});return}sfx('shoot');const count=st.spread+Math.floor((lv-1)/2),total=Math.min(.82,.13*(count-1)),start=-Math.PI/2-total/2,step=count===1?0:total/(count-1);for(let i=0;i<count;i++)createBullet(player.x,player.y-18,start+step*i,st.damage*(1+lv*.08),st)}function primaryFireInterval(st){const lv=weaponLevel();if(player.primaryWeapon==='missile')return st.fireRate*Math.max(1.45,2.25-lv*.08);if(player.primaryWeapon==='laser')return st.fireRate*Math.max(1.65,2.75-lv*.10);if(player.primaryWeapon==='heavy')return st.fireRate*Math.max(1.85,3.15-lv*.12);return st.fireRate}
function useSkill(skill){if(!state.running||state.paused||state.gameOver||skill.cdLeft>0)return;skillDefs[skill.id].use(skill.level);sfx('skill');skill.cdLeft=Math.max(1.5,skillDefs[skill.id].cd*(1-Math.min(.35,(skill.level-1)*.07)-Math.min(.45,player.cooldownMul)));renderSkillButtons()}function renderSkillButtons(forceRebuild=false){const box=q('skillBtns'),equipped=getEquippedSkills(),ids=equipped.map(sk=>sk.id).join('|');if(forceRebuild||box.dataset.skills!==ids||box.children.length!==equipped.length){box.innerHTML='';box.dataset.skills=ids;for(let i=0;i<equipped.length;i++){const sk=equipped[i],d=skillDefs[sk.id];if(!d)continue;const b=document.createElement('button');b.className='floatBtn skillBtn';b.dataset.skillId=sk.id;b.onclick=()=>{const current=state.skills.find(x=>x.id===b.dataset.skillId);if(current)useSkill(current)};box.appendChild(b)}}for(let i=0;i<equipped.length;i++){const sk=equipped[i],d=skillDefs[sk.id],b=box.children[i];if(!d||!b)continue;b.dataset.skillId=sk.id;b.className='floatBtn skillBtn '+(sk.cdLeft<=0?'ready':'cool');const prefix=!IS_TOUCH?`${i+1}.`:'';b.textContent=sk.cdLeft<=0?`${prefix}${d.short} Lv.${sk.level}`:`${prefix}${d.short} ${sk.cdLeft.toFixed(1)}s`}}
function skillMissile(level){const st=stats(),count=8+level*2,targets=nearestEnemies(count);for(let i=0;i<count;i++){const t=targets[i%Math.max(1,targets.length)],a=t?Math.atan2(t.y-player.y,t.x-player.x)+rand(-.12,.12):(-Math.PI/2+rand(-.8,.8));createBullet(player.x,player.y-18,a,st.damage*(3.4+level*.55),st,{pierce:1+Math.floor(level/2),color:'#ffe66d',r:st.bulletSize+2,life:1.8,homing:true})}addRing(player.x,player.y,60,'#ffe66d')}function skillShock(level){shockwave(175+level*28,80+level*45,30+level*5,'#63dfff')}function skillLaser(level){state.lasers.push({x:player.x,w:28+level*5,life:2.3+level*.2,dmg:70+level*32,tick:0})}function skillFreeze(level){state.slowTime=Math.max(state.slowTime,3.4+level*.45);addRing(player.x,player.y,Math.max(W,H),'#8dffce')}function skillStorm(level){const st=stats(),count=20+level*8;for(let i=0;i<count;i++){const a=i*Math.PI*2/count;createBullet(player.x,player.y,a,st.damage*(1.15+level*.22),st,{speed:520+level*35,r:st.bulletSize+1,life:1.35,pierce:1,color:'#ffe66d'})}addRing(player.x,player.y,150+level*25,'#ffe66d')}function skillBlackhole(level){const range=240+level*38,dmg=95+level*48;for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];if(sqr(e.x-player.x)+sqr(e.y-player.y)<sqr(range)){const dx=player.x-e.x,dy=player.y-e.y,l=Math.hypot(dx,dy)||1;e.x+=dx/l*(36+level*6);e.y+=dy/l*(36+level*6);hitEnemy(e,dmg);if(e.hp<=0)killEnemy(i,e)}}clearEnemyBullets(range);addRing(player.x,player.y,range,'#b46cff')}function skillRepair(level){const st=stats();player.hp=Math.min(st.maxHp,player.hp+55+level*35);player.shield+=35+level*22;addRing(player.x,player.y,110+level*18,'#4dff94')}function skillShieldOverload(level){player.shield+=60+level*32;player.tempArmor=Math.max(player.tempArmor,.16+level*.035);player.tempArmorTimer=Math.max(player.tempArmorTimer,4.5+level*.45);addRing(player.x,player.y,125+level*18,'#63dfff')}function skillSiphon(level){const range=170+level*24,dmg=45+level*26;let hit=0;for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];if(sqr(e.x-player.x)+sqr(e.y-player.y)<sqr(range)){hit++;hitEnemy(e,dmg);if(e.hp<=0)killEnemy(i,e)}}const st=stats();player.hp=Math.min(st.maxHp,player.hp+Math.min(75+level*18,hit*(5+level*2)));player.shield+=Math.min(45+level*10,hit*(3+level));addRing(player.x,player.y,range,'#ff7ac8')}function clearEnemyBullets(range){for(let i=state.enemyBullets.length-1;i>=0;i--){const b=state.enemyBullets[i];if(sqr(b.x-player.x)+sqr(b.y-player.y)<sqr(range))state.enemyBullets.splice(i,1)}}function shockwave(range,dmg,push,color){clearEnemyBullets(range);for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];if(sqr(e.x-player.x)+sqr(e.y-player.y)<sqr(range+e.r)){const dx=e.x-player.x,dy=e.y-player.y,l=Math.hypot(dx,dy)||1;e.x+=dx/l*push;e.y+=dy/l*push;hitEnemy(e,dmg);if(e.hp<=0)killEnemy(i,e)}}addRing(player.x,player.y,range,color)}function addRing(x,y,r,color){state.rings.push({x,y,r,life:.35,max:.35,color})}
function handleAutoWeapons(dt,st){if(player.autoLaser>0){player.autoLaserTimer-=dt;if(player.autoLaserTimer<=0){const t=nearestEnemies(1)[0];state.lasers.push({x:t?t.x:player.x,w:14+player.autoLaser*4,life:.42+player.autoLaser*.05,dmg:55+player.autoLaser*32,tick:0});player.autoLaserTimer=Math.max(1.05,2.75-player.autoLaser*.23)}}if(player.autoMissile>0){player.autoMissileTimer-=dt;if(player.autoMissileTimer<=0){const count=1+Math.floor(player.autoMissile/2),targets=nearestEnemies(count);for(let i=0;i<count;i++){const t=targets[i%Math.max(1,targets.length)],a=t?Math.atan2(t.y-player.y,t.x-player.x):(-Math.PI/2+rand(-.5,.5));createBullet(player.x,player.y-15,a,st.damage*(1.7+player.autoMissile*.38),st,{speed:570+player.autoMissile*22,r:st.bulletSize+1.5,life:2.2,color:'#ffe66d',pierce:0,homing:true})}player.autoMissileTimer=Math.max(.95,3.05-player.autoMissile*.26)}}if(player.orbitBall>0){player.orbitTimer-=dt;if(player.orbitTimer<=0){const c=Math.min(6,player.orbitBall);for(let k=0;k<c;k++){const a=state.time*2.7+k*Math.PI*2/c,ox=player.x+Math.cos(a)*54,oy=player.y+Math.sin(a)*36;for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];if(sqr(e.x-ox)+sqr(e.y-oy)<sqr(e.r+16)){hitEnemy(e,24+player.orbitBall*18);if(e.hp<=0)killEnemy(i,e)}}}player.orbitTimer=.18}}if(player.chainLightning>0){player.chainTimer-=dt;if(player.chainTimer<=0){fireChainLightning(player.chainLightning);player.chainTimer=Math.max(1.15,3.4-player.chainLightning*.22)}}if(player.autoShockwave>0){player.autoShockwaveTimer-=dt;if(player.autoShockwaveTimer<=0){shockwave(135+player.autoShockwave*24,28+player.autoShockwave*18,26+player.autoShockwave*5,'#63dfff');player.autoShockwaveTimer=Math.max(3.8,8.5-player.autoShockwave*.55)}}}function fireChainLightning(level){let point={x:player.x,y:player.y};const used=new Set(),jumps=2+level;for(let j=0;j<jumps;j++){let best=-1,bestD=999999;for(let i=0;i<state.enemies.length;i++){const e=state.enemies[i];if(used.has(e))continue;const d=sqr(e.x-point.x)+sqr(e.y-point.y);if(d<bestD&&d<sqr(240+level*18)){bestD=d;best=i}}if(best<0)break;const e=state.enemies[best];used.add(e);addRing(e.x,e.y,34+level*4,'#63dfff');hitEnemy(e,70+level*34);point={x:e.x,y:e.y};if(e.hp<=0)killEnemy(best,e)}}
function spawnEnemy(type='normal'){if(state.enemies.length>=MAX_ENEMIES&&type!=='boss')return;const side=pick([0,1,3]);let x,y;if(type==='boss'){x=W/2;y=-70}else if(side===0){x=rand(0,W);y=-45}else if(side===1){x=W+45;y=rand(55,H*.62)}else{x=-45;y=rand(55,H*.62)}const scale=difficultyScale(),e={x,y,type,hit:0,angle:0,age:0,shoot:rand(1.2,2.1)};if(type==='boss'){
  const kind=pick(['queen','fortress','storm','prism']);
  const cfg={
    queen:{name:'蜂后',color:'#ffcc33',hp:1.08,speed:30,damage:32,desc:'召唤蜂群'},
    fortress:{name:'重炮要塞',color:'#ff5533',hp:1.52,speed:24,damage:45,desc:'重型炮弹'},
    storm:{name:'雷暴母舰',color:'#63dfff',hp:1.16,speed:38,damage:33,desc:'环形弹幕'},
    prism:{name:'棱镜核心',color:'#b46cff',hp:1.24,speed:34,damage:37,desc:'交叉光束'}
  }[kind];
  const hp=1800*(1+state.wave*.16+state.score/6000)*cfg.hp;
  Object.assign(e,{r:50,hp,maxHp:hp,speed:cfg.speed,damage:cfg.damage,exp:120,score:1000,coin:120,color:cfg.color,maxLife:9999,boss:true,bossKind:kind,bossName:cfg.name,bossDesc:cfg.desc,cast:0,shoot:kind==='queen'?rand(1.05,1.75):rand(.78,1.35)});
  sfx('boss_start');state.bossAudioTimer=.9;
}else if(type==='fast')Object.assign(e,{r:11,hp:30*scale,maxHp:30*scale,speed:125+state.wave*3,damage:9,exp:4,score:12,coin:2,color:'#ffdd66',maxLife:16});else if(type==='shooter')Object.assign(e,{r:16,hp:72*scale,maxHp:72*scale,speed:46+state.wave,damage:13,exp:10,score:40,coin:6,color:'#4dff94',maxLife:30,shooter:true,shoot:rand(1,1.8)});else if(type==='tank')Object.assign(e,{r:24,hp:128*scale,maxHp:128*scale,speed:48+state.wave,damage:20,exp:12,score:45,coin:7,color:'#ff5f7e',maxLife:27});else if(type==='elite')Object.assign(e,{r:30,hp:285*scale,maxHp:285*scale,speed:44+state.wave,damage:28,exp:34,score:130,coin:22,color:'#b46cff',maxLife:44});else Object.assign(e,{r:15,hp:50*scale,maxHp:50*scale,speed:72+state.wave*2,damage:14,exp:7,score:22,coin:4,color:'#ff8a5c',maxLife:20});state.enemies.push(e)}function hitEnemy(e,dmg){
  if(e.boss&&e.bossKind==='queen'){
    const guard=state.enemies.find(x=>x.guard&&x.hp>0);
    if(guard){guard.hp-=dmg*.85;guard.hit=.06;return;}
  }
  e.hp-=dmg*(e.boss?1+player.bossDamageMul:1);e.hit=.06
}function killEnemy(index,e){state.score+=e.score;state.kills++;const st=stats(),coins=Math.max(1,Math.round(e.coin*(1+st.coinBonus)*rand(.9,1.25)));state.coins+=coins;dropGems(e);particles(e.x,e.y,e.color,e.boss?20:8,e.boss?1.6:.8);sfx(e.boss?'boss':'explode');if(e.boss){state.coins+=180;const rarity=randomRarity(.28),drops=[];const item=makeItem(rarity);state.inventory.push(item);drops.push(`装备：${item.name}`);if(Math.random()<.45){const wType=pick(weaponTypes);addWeaponMod(wType,rarity,false);const wLv=(player.weaponMods[wType]&&player.weaponMods[wType].level)||1;drops.push(`改装：${weaponTypeName(wType)} Lv.${wLv}`)}if(Math.random()<.35){const sId=pick(Object.keys(skillDefs));addOrUpgradeSkill(sId,rarity);const s=state.skills.find(x=>x.id===sId);drops.push(`主动：${skillDefs[sId].name} Lv.${s?s.level:1}`)}state.bossTimer=68;text(W/2,95,`击败${e.bossName||'BOSS'}！`,'#ffe66d');if(drops.length)text(W/2,121,`掉落：${drops.join(' ｜ ')}`,'#ffe66d')}state.enemies.splice(index,1)}function dropGems(e){const n=e.boss?12:e.type==='elite'?6:e.type==='tank'?3:1;for(let i=0;i<n;i++)state.gems.push({x:e.x+rand(-20,20),y:e.y+rand(-20,20),r:5,exp:Math.ceil(e.exp/n),vx:rand(-50,50),vy:rand(-50,50),life:16})}function particles(x,y,color,count=8,power=1){if(LOW||state.particles.length>MAX_PARTICLES)return;for(let i=0;i<count;i++){const a=rand(0,Math.PI*2),s=rand(35,170)*power;state.particles.push({x,y,vx:Math.cos(a)*s,vy:Math.sin(a)*s,r:rand(1.4,4)*power,life:rand(.2,.55),max:.55,color})}}function text(x,y,msg,color='#fff'){if(LOW)return;state.texts.push({x,y,msg,color,life:.7,vy:-30})}function bossShoot(e){
  e.cast=(e.cast||0)+1;
  if(e.bossKind==='queen'){
    if(e.cast%2===1) summonBossMinions(e,'beeShooter',15);
    else summonBossMinions(e,'workerBee',15);
    return;
  }
  if(e.bossKind==='fortress'){
    const base=Math.atan2(player.y-e.y,player.x-e.x);
    for(let i=0;i<4;i++){
      const a=base+(i-1.5)*.16;
      state.enemyBullets.push({x:e.x,y:e.y+e.r*.35,vx:Math.cos(a)*122,vy:Math.sin(a)*122,r:13,damage:22+state.score/2800,life:6,color:'#ff9966'});
    }
    return;
  }
  if(e.bossKind==='storm'){
    const count=LOW?14:20;
    const spin=state.time*.9;
    for(let i=0;i<count;i++){
      const a=spin+i*Math.PI*2/count;
      state.enemyBullets.push({x:e.x,y:e.y,vx:Math.cos(a)*135,vy:Math.sin(a)*135,r:5,damage:11+state.score/3600,life:5,color:'#63dfff'});
    }
    return;
  }
  if(e.bossKind==='prism'){
    const base=Math.atan2(player.y-e.y,player.x-e.x);
    for(let lane=-2;lane<=2;lane++){
      const a=base+lane*.22;
      for(let j=0;j<3;j++) state.enemyBullets.push({x:e.x+lane*10,y:e.y+e.r*.2+j*12,vx:Math.cos(a)*(170+j*24),vy:Math.sin(a)*(170+j*24),r:4,damage:10+state.score/3800,life:4.2,color:'#b46cff'});
    }
    return;
  }
  const base=Math.atan2(player.y-e.y,player.x-e.x),count=LOW?5:7;
  for(let i=0;i<count;i++){const a=base+(i-(count-1)/2)*.18;state.enemyBullets.push({x:e.x,y:e.y+e.r*.4,vx:Math.cos(a)*155,vy:Math.sin(a)*155,r:7,damage:14,life:5})}
}
function summonBossMinions(boss,type,count){
  let made=0;
  for(let i=0;i<count;i++){
    if(state.enemies.length>=MAX_ENEMIES+18) break;
    const a=i*Math.PI*2/count+rand(-.08,.08);
    const d=type==='workerBee'?rand(42,82):rand(55,110);
    const x=boss.x+Math.cos(a)*d;
    const y=boss.y+Math.sin(a)*d;
    const scale=difficultyScale();
    if(type==='workerBee'){
      state.enemies.push({x,y,type:'workerBee',hit:0,angle:0,age:0,r:10,hp:42*scale,maxHp:42*scale,speed:95,damage:8,exp:2,score:8,coin:1,color:'#ffd166',maxLife:18,guard:true,shoot:9});
    }else{
      state.enemies.push({x,y,type:'beeShooter',hit:0,angle:0,age:0,r:10,hp:34*scale,maxHp:34*scale,speed:82,damage:8,exp:3,score:10,coin:1,color:'#ffee88',maxLife:20,shooter:true,shoot:rand(.8,1.7)});
    }
    made++;
  }
  if(made>0) addRing(boss.x,boss.y,type==='workerBee'?105:130,type==='workerBee'?'#ffd166':'#ffee88');
}function enemyShoot(e){const a=Math.atan2(player.y-e.y,player.x-e.x);state.enemyBullets.push({x:e.x,y:e.y,vx:Math.cos(a)*135,vy:Math.sin(a)*135,r:5,damage:10+state.score/2500,life:4})}
function damagePlayer(amount){if(player.invincible>0)return;let left=amount;if(player.shield>0){const used=Math.min(player.shield,left);player.shield-=used;left-=used}if(left>0)player.hp-=left*Math.max(.3,1-Math.min(.7,player.armor+(player.tempArmor||0)));player.invincible=.65;state.shake=.16;sfx('hurt');if(player.hp<=0)endGame()}function gainExp(a){player.exp+=a*(1+player.expBonus);let shouldOpen=false;while(player.exp>=player.expNeed){player.exp-=player.expNeed;player.level++;player.expNeed=Math.floor(player.expNeed*1.28+8);player.hp=Math.min(stats().maxHp,player.hp+18);state.pendingUpgrades++;sfx('level');if(settings.upgradeMode==='auto')shouldOpen=true}updateSettingsUi();if(shouldOpen&&!state.paused&&!state.gameOver&&q('upgradePanel').classList.contains('hidden'))openUpgradePanel()}
function makeSkillOffer(){const id=pick(Object.keys(skillDefs)),owned=state.skills.find(s=>s.id===id),rarity=randomRarity(.03);return{type:'skill',skillId:id,rarity,cost:Math.round((owned?75+owned.level*45:70)*rarityInfo[rarity].mul)}}function makeWeaponModOffer(){const type=pick(weaponTypes),rarity=randomRarity(.04);return{type:'weaponMod',weaponType:type,rarity,cost:Math.round((68+rarityPower[rarity]*25)*rarityInfo[rarity].mul)}}function makeShopOffer(){const r=Math.random();if(r<.14)return makeSkillOffer();if(r<.26)return makeWeaponModOffer();return{type:'item',item:makeItem()}}function generateShop(){state.shopOffers=Array.from({length:5},makeShopOffer)}
function openUpgradePanel(){if(state.pendingUpgrades<=0||state.gameOver)return;state.pendingUpgrades--;state.paused=true;updateSettingsUi();q('upgradePanel').classList.remove('hidden');q('upgradeList').innerHTML='';const choices=[];while(choices.length<3){const roll=Math.random();if(roll<.14){const id=pick(Object.keys(skillDefs)),rarity=randomRarity(.02);choices.push({rarity,name:state.skills.find(s=>s.id===id)?`升级主动：${skillText(id)}`:`解锁主动：${skillDefs[id].name}`,desc:skillDefs[id].desc,apply:()=>addOrUpgradeSkill(id,rarity)})}else if(roll<.26){const type=pick(weaponTypes),rarity=randomRarity(.02);choices.push({rarity,name:`主武器改装：${weaponTypeName(type)}`,desc:'获得后会加入背包的主武器改装列表，可随时切换。',apply:()=>addWeaponMod(type,rarity)})}else{const pool=passiveUpgrades.filter(u=>!u.rare||Math.random()<.35);const up=pick(pool.length?pool:passiveUpgrades);choices.push({...up,rarity:up.rare?'rare':'common',apply:()=>gainPassiveUpgrade(up.id)})}}for(const up of choices){const d=document.createElement('div'),rr=up.rarity||'common';d.className='upgrade '+rarityCls(rr);d.innerHTML=`<strong>${up.name}</strong><span><span class="tag">${rarityName(rr)}</span>${up.desc}</span>`;d.onclick=()=>{sfx('buy');up.apply();resumeGame();updateHud()};q('upgradeList').appendChild(d)}}
function pauseGame(){state.paused=true}function resumeGame(){['inventoryPanel','passivePanel','shopPanel','upgradePanel','settingsPanel'].forEach(id=>q(id).classList.add('hidden'));if(!state.gameOver){if(settings.upgradeMode==='auto'&&state.pendingUpgrades>0){openUpgradePanel();return}state.paused=false;state.lastFrame=performance.now();requestAnimationFrame(loop)}}
function renderPassivePanel(){q('passiveList').innerHTML=state.passives.map(p=>{const up=passiveUpgradeMap[p.id],r=p.rarity||'common';if(!up)return'';return`<div class="slotCard ${rarityCls(r)}"><strong><span class="tag">${rarityName(r)}${p.count>1?` · x${p.count}`:''}</span>${up.name}</strong><span>${up.desc}${p.count>1?`<br>当前已叠加 ${p.count} 次。`:''}</span></div>`}).join('')||'<div class="empty">暂时还没有拿到被动强化</div>'}
function renderInventory(){const equippedIds=state.equippedSkills;q('skillList').innerHTML=state.skills.map(s=>{const d=skillDefs[s.id],r=s.rarity||'common',eqIdx=equippedIds.indexOf(s.id),equipped=eqIdx>=0,hotkey=!IS_TOUCH&&equipped?`<span class="tag">按键 ${eqIdx+1}</span>`:'',status=equipped?'✅ 已装备':'点击装备（最多 3 个）';return`<div class="slotCard ${rarityCls(r)}" data-skill-toggle="${s.id}"><strong><span class="tag">${rarityName(r)}</span>${d.name} Lv.${s.level}</strong><span>${d.desc}<br>冷却：${s.cdLeft.toFixed(1)} 秒<br>${status}${hotkey}</span></div>`}).join('')||'<div class="empty">暂无主动技能</div>';[...q('skillList').querySelectorAll('[data-skill-toggle]')].forEach(el=>{el.onclick=()=>{const id=el.dataset.skillToggle;if(isSkillEquipped(id)){sfx('ui');unequipSkill(id);renderInventory();updateHud();return}if(equipSkill(id)){sfx('ui');renderInventory();updateHud()}else sfx('bad')}});const mods=player.weaponMods||{bullet:{level:1,rarity:'common'}};q('weaponModList').innerHTML=Object.entries(mods).map(([type,mod])=>{const active=player.primaryWeapon===type,r=mod.rarity||'common';return`<div class="item ${rarityCls(r)}" data-weapon="${type}"><div class="row"><strong>${active?'✅ ':''}${weaponTypeName(type)} Lv.${mod.level||1}</strong><span class="tag">${rarityName(r)}</span></div><span>${active?'当前使用中':'点击切换为主武器'}</span></div>`}).join('');[...q('weaponModList').querySelectorAll('[data-weapon]')].forEach(el=>{el.onclick=()=>{sfx('ui');switchPrimaryWeapon(el.dataset.weapon);renderInventory();updateHud()}});q('equipSlots').innerHTML='';for(const slot of slotOrder){const id=state.equipped[slot],it=state.inventory.find(x=>x.id===id),d=document.createElement('div');d.className='slotCard '+(it?rarityCls(it.rarity):'');d.innerHTML=it?`<strong><span class="tag">${rarityName(it.rarity)}</span>${slot}：${it.name}</strong><span>${it.desc}<br>${statText(it.stats)}</span>`:`<strong>${slot}：未装备</strong><span>可在商店或 Boss 奖励中获得装备。</span>`;q('equipSlots').appendChild(d)}q('inventoryList').innerHTML='';if(!state.inventory.length){q('inventoryList').innerHTML='<div class="empty">背包为空</div>';return}for(const it of state.inventory){const eq=state.equipped[it.slot]===it.id,d=document.createElement('div');d.className='item '+rarityCls(it.rarity);d.innerHTML=`<div class="row"><strong>${it.name}</strong><span class="tag">${rarityName(it.rarity)} · ${it.slot}</span></div><span>${it.desc}<br>${statText(it.stats)}${eq?'<br>✅ 已装备':'<br>点击装备'}</span>`;d.onclick=()=>{sfx('ui');const before=stats().maxHp;state.equipped[it.slot]=it.id;const after=stats().maxHp;if(after>before)player.hp+=after-before;if(it.stats.shieldBonus)player.shield=Math.max(player.shield,it.stats.shieldBonus);player.hp=Math.min(player.hp,after);renderInventory();updateHud()};q('inventoryList').appendChild(d)}}
function renderShop(){q('shopCoinText').textContent=`金币：${state.coins}`;q('shopList').innerHTML='';state.shopOffers.forEach((offer,i)=>{if(!offer)return;const d=document.createElement('div');if(offer.type==='skill'){const def=skillDefs[offer.skillId],owned=state.skills.find(s=>s.id===offer.skillId),r=offer.rarity||'common';d.className='item '+rarityCls(r);d.innerHTML=`<div class="row"><strong>${owned?'升级主动：':'购买主动：'}${def.name}</strong><span class="price">${offer.cost} 金币</span></div><span><span class="tag">${rarityName(r)} · 主动技能</span>${def.desc}${owned?`<br>当前 Lv.${owned.level} → Lv.${owned.level+(rarityPower[r]||1)}`:''}</span>`;d.onclick=()=>{if(state.coins<offer.cost)return flash(d);state.coins-=offer.cost;sfx('buy');addOrUpgradeSkill(offer.skillId,r);state.shopOffers[i]=null;renderShop();updateHud()}}else if(offer.type==='weaponMod'){const r=offer.rarity||'common';d.className='item '+rarityCls(r);d.innerHTML=`<div class="row"><strong>主武器改装：${weaponTypeName(offer.weaponType)}</strong><span class="price">${offer.cost} 金币</span></div><span><span class="tag">${rarityName(r)} · 改装</span>购买后进入主武器改装列表，可在背包切换。</span>`;d.onclick=()=>{if(state.coins<offer.cost)return flash(d);state.coins-=offer.cost;sfx('buy');addWeaponMod(offer.weaponType,r);state.shopOffers[i]=null;renderShop();updateHud()}}else{const it=offer.item;d.className='item '+rarityCls(it.rarity);d.innerHTML=`<div class="row"><strong>${it.name}</strong><span class="price">${it.cost} 金币</span></div><span><span class="tag">${rarityName(it.rarity)} · ${it.slot}</span>${it.desc}<br>${statText(it.stats)}</span>`;d.onclick=()=>{if(state.coins<it.cost)return flash(d);state.coins-=it.cost;sfx('buy');state.inventory.push(it);state.shopOffers[i]=null;renderShop();updateHud()}}q('shopList').appendChild(d)});if(!q('shopList').children.length)q('shopList').innerHTML='<div class="empty">商品已售空，可以刷新商店。</div>'}function flash(el){sfx('bad');el.style.opacity='.45';setTimeout(()=>el.style.opacity='1',160)}
function keyVec(){let x=0,y=0;if(input.keys.has('arrowleft')||input.keys.has('a'))x--;if(input.keys.has('arrowright')||input.keys.has('d'))x++;if(input.keys.has('arrowup')||input.keys.has('w'))y--;if(input.keys.has('arrowdown')||input.keys.has('s'))y++;const l=Math.hypot(x,y);return l>1?{x:x/l,y:y/l}:{x,y}}
function update(dt){if(state.paused||state.gameOver)return;state.time+=dt;state.wave=1+Math.floor(state.time/25);state.slowTime=Math.max(0,state.slowTime-dt);state.shake=Math.max(0,state.shake-dt);player.invincible=Math.max(0,player.invincible-dt);player.tempArmorTimer=Math.max(0,player.tempArmorTimer-dt);if(player.tempArmorTimer<=0)player.tempArmor=0;const st=stats();player.hp=Math.min(player.hp,st.maxHp);for(const s of state.stars){s.y+=s.s*dt;if(s.y>H+5){s.y=-5;s.x=Math.random()*W}}if(input.touching){const dx=input.targetX-player.x,dy=input.targetY-player.y,d=Math.hypot(dx,dy),step=Math.max(st.speed*1.65,720)*dt;if(d<=step){player.x=input.targetX;player.y=input.targetY}else{player.x+=dx/d*step;player.y+=dy/d*step}}else{const v=keyVec();const keySpeed=Math.max(st.speed*1.65,720);player.x+=v.x*keySpeed*dt;player.y+=v.y*keySpeed*dt}player.x=clamp(player.x,22,W-22);player.y=clamp(player.y,60,H-24);player.fireTimer-=dt;if(player.fireTimer<=0){shoot();player.fireTimer=primaryFireInterval(st)}if(player.regen>0){player.regenTimer-=dt;if(player.regenTimer<=0){player.hp=Math.min(st.maxHp,player.hp+player.regen*(2.5+state.time/180));player.regenTimer=1}}if(player.drone>0){player.droneTimer-=dt;if(player.droneTimer<=0){for(let i=0;i<player.drone;i++)createBullet(player.x+(i-(player.drone-1)/2)*24,player.y+8,-Math.PI/2+rand(-.3,.3),st.damage*.58,st,{r:st.bulletSize*.8});player.droneTimer=Math.max(.13,.5-player.drone*.07)}}handleAutoWeapons(dt,st);const diff=difficultyScale();state.enemySpawnTimer-=dt;const spawnInt=Math.max(.14,.86-state.wave*.038-state.score/15000);if(state.enemySpawnTimer<=0){const r=Math.random();if(state.score>900&&r<Math.min(.2,(diff-1)*.065))spawnEnemy('shooter');else if(r<Math.min(.18,state.wave*.018))spawnEnemy('tank');else if(r<.36)spawnEnemy('fast');else spawnEnemy('normal');state.enemySpawnTimer=spawnInt}state.eliteTimer-=dt;if(state.eliteTimer<=0){spawnEnemy('elite');state.eliteTimer=Math.max(13,24-state.wave)}state.bossTimer-=dt;if(state.bossTimer<=0&&!state.enemies.some(e=>e.boss)){spawnEnemy('boss');state.bossTimer=999;text(W/2,90,'大BOSS出现！','#ff335f')}const activeBoss=state.enemies.find(e=>e.boss);if(activeBoss){state.bossAudioTimer-=dt;if(state.bossAudioTimer<=0){sfx('boss_loop');state.bossAudioTimer=1.45}}for(const sk of state.skills)sk.cdLeft=Math.max(0,sk.cdLeft-dt);state.skillUiTick+=dt;if(state.skillUiTick>.18){state.skillUiTick=0;renderSkillButtons()}for(let i=state.bullets.length-1;i>=0;i--){const b=state.bullets[i];if(b.homing){const t=nearestEnemies(1)[0];if(t){const sp=Math.hypot(b.vx,b.vy)||520,a=Math.atan2(t.y-b.y,t.x-b.x);b.vx=b.vx*.9+Math.cos(a)*sp*.1;b.vy=b.vy*.9+Math.sin(a)*sp*.1}}b.x+=b.vx*dt;b.y+=b.vy*dt;b.life-=dt;if(b.life<=0||b.x<-70||b.x>W+70||b.y<-100||b.y>H+100)state.bullets.splice(i,1)}const slowMul=state.slowTime>0?.35:1;for(let i=state.enemyBullets.length-1;i>=0;i--){const b=state.enemyBullets[i];b.x+=b.vx*dt*slowMul;b.y+=b.vy*dt*slowMul;b.life-=dt;if(b.life<=0||b.x<-50||b.x>W+50||b.y<-50||b.y>H+50)state.enemyBullets.splice(i,1);else if(sqr(b.x-player.x)+sqr(b.y-player.y)<sqr(b.r+player.r)){damagePlayer(b.damage);state.enemyBullets.splice(i,1)}}for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];e.age+=dt;e.hit=Math.max(0,e.hit-dt);if(!e.boss&&e.age>e.maxLife){state.enemies.splice(i,1);continue}const dx=player.x-e.x,dy=player.y-e.y,l=Math.hypot(dx,dy)||1,sp=e.speed*slowMul;if(e.boss){if(e.y<90)e.y+=e.speed*dt;else{e.x+=Math.sin(state.time*.65)*18*dt;e.y+=Math.sin(state.time*.9)*8*dt}}else{e.x+=dx/l*sp*dt;e.y+=dy/l*sp*dt}e.angle+=dt*3*slowMul;if(sqr(e.x-player.x)+sqr(e.y-player.y)<sqr(e.r+player.r)){damagePlayer(e.damage);if(!e.boss){state.enemies.splice(i,1);continue}}if(e.boss){e.shoot-=dt;if(e.shoot<=0){bossShoot(e);const baseCd=Math.max(.55,1.2-state.wave*.025-state.score/30000);e.shoot=e.bossKind==='queen'?baseCd:Math.max(.42,baseCd*.8)}}else if(e.shooter){e.shoot-=dt*slowMul;if(e.shoot<=0){enemyShoot(e);e.shoot=Math.max(.95,2.15-state.score/16000)}}}for(let li=state.lasers.length-1;li>=0;li--){const l=state.lasers[li];l.life-=dt;l.tick-=dt;if(l.tick<=0){l.tick=.12;for(let i=state.enemies.length-1;i>=0;i--){const e=state.enemies[i];if(Math.abs(e.x-l.x)<l.w+e.r&&e.y<player.y+40){hitEnemy(e,l.dmg);if(e.hp<=0)killEnemy(i,e)}}}if(l.life<=0)state.lasers.splice(li,1)}for(let bi=state.bullets.length-1;bi>=0;bi--){const b=state.bullets[bi];for(let ei=state.enemies.length-1;ei>=0;ei--){const e=state.enemies[ei];if(sqr(b.x-e.x)+sqr(b.y-e.y)<sqr(b.r+e.r)){hitEnemy(e,b.damage);if(e.hp<=0)killEnemy(ei,e);if(b.pierce>0)b.pierce--;else state.bullets.splice(bi,1);break}}}for(let i=state.gems.length-1;i>=0;i--){const g=state.gems[i];g.life-=dt;g.x+=g.vx*dt;g.y+=g.vy*dt;g.vx*=Math.pow(.08,dt);g.vy*=Math.pow(.08,dt);const dx=player.x-g.x,dy=player.y-g.y,d2=dx*dx+dy*dy,mag=st.magnet;if(d2<mag*mag){const d=Math.sqrt(d2)||1,pull=760*(1-d/mag);g.x+=dx/d*pull*dt;g.y+=dy/d*pull*dt}if(d2<sqr(player.r+g.r+4)){gainExp(g.exp);sfx('pickup');state.gems.splice(i,1)}else if(g.life<=0)state.gems.splice(i,1)}if(!LOW){for(let i=state.particles.length-1;i>=0;i--){const p=state.particles[i];p.life-=dt;p.x+=p.vx*dt;p.y+=p.vy*dt;if(p.life<=0)state.particles.splice(i,1)}for(let i=state.texts.length-1;i>=0;i--){const t=state.texts[i];t.life-=dt;t.y+=t.vy*dt;if(t.life<=0)state.texts.splice(i,1)}}for(let i=state.rings.length-1;i>=0;i--){state.rings[i].life-=dt;if(state.rings[i].life<=0)state.rings.splice(i,1)}updateHud()}
function updateHud(){const st=stats();q('leftInfo').textContent=`Lv.${player.level} | ${weaponName()} | 分数 ${Math.floor(state.score)} | 波次 ${state.wave}`;q('rightInfo').textContent=`金币 ${state.coins} | 击杀 ${state.kills}`;q('hpBar').style.width=clamp(player.hp/st.maxHp*100,0,100)+'%';q('expBar').style.width=clamp(player.exp/player.expNeed*100,0,100)+'%';const boss=state.enemies.find(e=>e.boss);if(boss){q('bossHud').classList.remove('hidden');q('bossText').textContent=`${boss.bossName||'BOSS'} · ${boss.bossDesc||''}`;q('bossBar').style.width=clamp(boss.hp/boss.maxHp*100,0,100)+'%'}else q('bossHud').classList.add('hidden')}
function draw(){ctx.fillStyle='#050816';ctx.fillRect(0,0,W,H);const sx=state.shake>0?rand(-5,5)*state.shake*3:0,sy=state.shake>0?rand(-5,5)*state.shake*3:0;ctx.save();ctx.translate(sx,sy);ctx.fillStyle='#fff';for(const s of state.stars){ctx.globalAlpha=s.a;if(LOW)ctx.fillRect(s.x,s.y,Math.max(1,s.r),Math.max(1,s.r));else{ctx.beginPath();ctx.arc(s.x,s.y,s.r,0,Math.PI*2);ctx.fill()}}ctx.globalAlpha=1;for(const g of state.gems){ctx.fillStyle='#63dfff';ctx.fillRect(g.x-4,g.y-4,8,8)}for(const b of state.bullets){ctx.fillStyle=b.color||(b.crit?'#ffe66d':'#d9fbff');ctx.beginPath();ctx.arc(b.x,b.y,b.r,0,Math.PI*2);ctx.fill()}for(const b of state.enemyBullets){ctx.fillStyle='#ff4769';ctx.beginPath();ctx.arc(b.x,b.y,b.r,0,Math.PI*2);ctx.fill()}for(const e of state.enemies)drawEnemy(e);for(const l of state.lasers){ctx.globalAlpha=.55;ctx.fillStyle='#b46cff';ctx.fillRect(l.x-l.w/2,0,l.w,player.y+40);ctx.globalAlpha=1}drawPlayer();if(!LOW){for(const p of state.particles){ctx.globalAlpha=Math.max(0,p.life/p.max);ctx.fillStyle=p.color;ctx.fillRect(p.x,p.y,p.r,p.r)}for(const t of state.texts){ctx.globalAlpha=Math.max(0,t.life/.7);ctx.fillStyle=t.color;ctx.font='bold 15px system-ui';ctx.textAlign='center';ctx.fillText(t.msg,t.x,t.y)}ctx.globalAlpha=1}for(const r of state.rings){ctx.globalAlpha=Math.max(0,r.life/r.max);ctx.strokeStyle=r.color;ctx.lineWidth=3;ctx.beginPath();ctx.arc(r.x,r.y,r.r*(1-r.life/r.max),0,Math.PI*2);ctx.stroke()}ctx.globalAlpha=1;ctx.restore()}function drawPlayer(){ctx.save();ctx.translate(player.x,player.y);if(player.invincible>0)ctx.globalAlpha=.55;ctx.fillStyle='#63dfff';ctx.beginPath();ctx.moveTo(0,-22);ctx.lineTo(16,18);ctx.lineTo(0,10);ctx.lineTo(-16,18);ctx.closePath();ctx.fill();ctx.fillStyle='#fff';ctx.fillRect(-5,-8,10,16);ctx.fillStyle='#ffe66d';ctx.fillRect(-5,18,10,9);ctx.restore();if(player.shield>0){ctx.strokeStyle='#63dfff';ctx.lineWidth=2;ctx.beginPath();ctx.arc(player.x,player.y,player.r+10,0,Math.PI*2);ctx.stroke()}if(player.drone>0){ctx.fillStyle='#b46cff';for(let i=0;i<player.drone;i++){const a=state.time*2.4+i*Math.PI*2/player.drone;ctx.beginPath();ctx.arc(player.x+Math.cos(a)*42,player.y+Math.sin(a)*26,5,0,Math.PI*2);ctx.fill()}}if(player.orbitBall>0){const c=Math.min(6,player.orbitBall);ctx.fillStyle='#63dfff';for(let i=0;i<c;i++){const a=state.time*2.7+i*Math.PI*2/c;ctx.beginPath();ctx.arc(player.x+Math.cos(a)*54,player.y+Math.sin(a)*36,7,0,Math.PI*2);ctx.fill()}}}function drawEnemy(e){ctx.save();ctx.translate(e.x,e.y);ctx.rotate(e.angle);ctx.fillStyle=e.hit>0?'#fff':e.color;if(e.boss){ctx.beginPath();ctx.arc(0,0,e.r,0,Math.PI*2);ctx.fill();ctx.fillStyle='#ffccd5';ctx.fillRect(-22,-8,44,16)}else if(e.type==='fast'){ctx.beginPath();ctx.moveTo(0,-e.r);ctx.lineTo(e.r,e.r);ctx.lineTo(-e.r,e.r);ctx.closePath();ctx.fill()}else if(e.shooter){ctx.beginPath();ctx.moveTo(0,-e.r);ctx.lineTo(e.r,e.r);ctx.lineTo(0,e.r*.45);ctx.lineTo(-e.r,e.r);ctx.closePath();ctx.fill()}else ctx.fillRect(-e.r,-e.r,e.r*2,e.r*2);ctx.restore();if(e.hp<e.maxHp&&!e.boss){const w=e.r*2;ctx.fillStyle='rgba(255,255,255,.18)';ctx.fillRect(e.x-e.r,e.y-e.r-8,w,3);ctx.fillStyle='#ff4d6d';ctx.fillRect(e.x-e.r,e.y-e.r-8,w*(e.hp/e.maxHp),3)}}
function endGame(){state.running=false;state.gameOver=true;sfx('gameover');q('bottomControls').classList.add('hidden');q('gameOverPanel').classList.remove('hidden');q('finalStats').innerHTML=`最终分数：<b>${Math.floor(state.score)}</b><br>金币：<b>${state.coins}</b><br>生存时间：<b>${Math.floor(state.time)} 秒</b><br>等级：<b>${player.level}</b>　击杀：<b>${state.kills}</b>`}function loop(now){if(!state.running)return;if(now-state.lastRender<TARGET_FRAME){requestAnimationFrame(loop);return}const dt=Math.min(.05,(now-state.lastFrame)/1000||.016),gameDt=dt*settings.gameSpeed;state.lastFrame=now;state.lastRender=now;update(gameDt);draw();if(state.running&&!state.paused)requestAnimationFrame(loop)}
q('upgradeBtn').onclick=()=>{if(!state.running||state.gameOver||state.pendingUpgrades<=0)return;sfx('ui');openUpgradePanel()};q('settingsBtn').onclick=()=>{if(!state.running||state.gameOver)return;sfx('ui');pauseGame();updateSettingsUi();q('settingsPanel').classList.remove('hidden')};q('toggleSoundBtn').onclick=()=>{unlockAudio();audio.muted=!audio.muted;updateSettingsUi();sfx('ui')};q('speedSlider').oninput=e=>{settings.gameSpeed=+e.target.value;updateSettingsUi()};q('upgradeModeAutoBtn').onclick=()=>{settings.upgradeMode='auto';updateSettingsUi();sfx('ui')};q('upgradeModeManualBtn').onclick=()=>{settings.upgradeMode='manual';updateSettingsUi();sfx('ui')};q('passiveBtn').onclick=()=>{if(!state.running||state.gameOver)return;sfx('ui');pauseGame();renderPassivePanel();q('passivePanel').classList.remove('hidden')};q('bagBtn').onclick=()=>{if(!state.running||state.gameOver)return;sfx('ui');pauseGame();renderInventory();q('inventoryPanel').classList.remove('hidden')};q('shopBtn').onclick=()=>{if(!state.running||state.gameOver)return;sfx('ui');pauseGame();renderShop();q('shopPanel').classList.remove('hidden')};q('closePassiveBtn').onclick=()=>{sfx('ui');resumeGame()};q('closeBagBtn').onclick=()=>{sfx('ui');resumeGame()};q('closeShopBtn').onclick=()=>{sfx('ui');resumeGame()};q('closeSettingsBtn').onclick=()=>{sfx('ui');resumeGame()};q('refreshShopBtn').onclick=()=>{if(state.coins<15)return sfx('bad');state.coins-=15;sfx('buy');generateShop();renderShop();updateHud()};function safeStart(e){if(e){e.preventDefault();e.stopPropagation()}const now=performance.now();if(safeStart.last&&now-safeStart.last<220)return;safeStart.last=now;unlockAudio();sfx('start');resetGame()}q('startBtn').addEventListener('click',safeStart);q('startBtn').addEventListener('pointerup',safeStart,{passive:false});q('restartBtn').addEventListener('click',safeStart);q('restartBtn').addEventListener('pointerup',safeStart,{passive:false});updateSettingsUi();
draw();
